var distributeCandies = function(candies, num_people) {
    const ans = new Array(num_people).fill(0);
    let give = 1, idx = 0;
    while (candies > 0) {
        const take = Math.min(give, candies);
        ans[idx] += take;
        candies -= take;
        give += 1;
        idx += 1;
        if (idx === num_people) idx = 0;
    }
    return ans;
};
